var gs_chapter1 = {
  name: "الفصل 1 و 2: الالتهاب، السوائل والكهارل",
  icon: "fas fa-notes-medical",

  mcq: [
    {text:"Which of the following is a local sign of acute inflammation?", translation:"أي مما يلي من العلامات الموضعية للالتهاب الحاد؟", options:["a) Fever","b) Redness (Rubor)","c) Leukocytosis","d) Headache"], correct:"b) Redness (Rubor)", correctTranslation:"الاحمرار (Rubor) من العلامات الموضعية الخمس للالتهاب"},
    {text:"A localized collection of pus in the tissues is called:", translation:"تجمع موضعي للصديد داخل الأنسجة يُسمى:", options:["a) Cellulitis","b) Abscess","c) Ulcer","d) Gangrene"], correct:"b) Abscess", correctTranslation:"الخُراج (Abscess)"},
    {text:"The main intracellular cation (inside the cell) is:", translation:"الكاتيون الرئيسي داخل الخلية هو:", options:["a) Sodium","b) Potassium","c) Calcium","d) Chloride"], correct:"b) Potassium", correctTranslation:"البوتاسيوم (K+) هو الكاتيون الرئيسي داخل الخلايا"},
    {text:'"Risus Sardonicus" or sardonic smile is a clinical feature of:', translation:'الابتسامة الساخرة "التشنجية" علامة سريرية في مرض:', options:["a) Gas Gangrene","b) Tetanus","c) Cellulitis","d) Septicemia"], correct:"b) Tetanus", correctTranslation:"الكزاز (Tetanus)"},
    {text:"The normal range of serum Sodium (Na+) is:", translation:"المعدل الطبيعي لصوديوم المصل هو:", options:["a) 3.5 - 5.0 mEq/L","b) 135 - 145 mEq/L","c) 9 - 11 mg/dL","d) 98 - 106 mEq/L"], correct:"b) 135 - 145 mEq/L", correctTranslation:"135 - 145 ملي مكافئ/لتر"},
    {text:"Diffuse inflammation of the subcutaneous connective tissue is:", translation:"التهاب منتشر في النسيج الضام تحت الجلد يُسمى:", options:["a) Abscess","b) Boil","c) Cellulitis","d) Carbuncle"], correct:"c) Cellulitis", correctTranslation:"التهاب النسيج الخلوي (Cellulitis)"},
    {text:"The organism responsible for Gas Gangrene is:", translation:"الميكروب المسبب للغرغرينا الغازية هو:", options:["a) Staphylococcus","b) Streptococcus","c) Clostridium Welchii","d) E-coli"], correct:"c) Clostridium Welchii", correctTranslation:"المطثية الحاطمة (Clostridium Welchii)"},
    {text:"Hypokalemia refers to a low blood level of:", translation:"نقص بوتاسيوم الدم يعني انخفاض مستوى:", options:["a) Sodium","b) Potassium","c) Calcium","d) Magnesium"], correct:"b) Potassium", correctTranslation:"البوتاسيوم"},
    {text:"Which type of shock is caused by severe hemorrhage (bleeding)?", translation:"أي نوع من الصدمة يحدث نتيجة نزيف حاد؟", options:["a) Septic shock","b) Hypovolemic shock","c) Neurogenic shock","d) Anaphylactic shock"], correct:"b) Hypovolemic shock", correctTranslation:"صدمة نقص الحجم (Hypovolemic shock)"},
    {text:"A cluster of furuncles connected under the skin with multiple openings is:", translation:"تجمع من الدمامل المتصلة تحت الجلد بفتحات متعددة يُسمى:", options:["a) Abscess","b) Carbuncle","c) Cellulitis","d) Cyst"], correct:"b) Carbuncle", correctTranslation:"الجمرة الخبيثة الجلدية (Carbuncle)"},
    {text:"The movement of water from low solute concentration to high solute concentration is:", translation:"انتقال الماء من تركيز مذاب منخفض إلى تركيز مرتفع عبر غشاء شبه منفذ هو:", options:["a) Diffusion","b) Osmosis","c) Active transport","d) Filtration"], correct:"b) Osmosis", correctTranslation:"التناضح (Osmosis)"},
    {text:"Specific inflammation is caused by:", translation:"الالتهاب النوعي يسببه:", options:["a) Staphylococci","b) Mycobacterium Tuberculosis","c) Streptococci","d) Pneumococci"], correct:"b) Mycobacterium Tuberculosis", correctTranslation:"عصية السل (Mycobacterium TB)"},
    {text:"Which electrolyte is essential for blood clotting and bone formation?", translation:"أي إلكتروليت ضروري لتخثر الدم وتكوين العظام؟", options:["a) Sodium","b) Potassium","c) Calcium","d) Chloride"], correct:"c) Calcium", correctTranslation:"الكالسيوم"},
    {text:"In Tetanus, the first muscle group usually affected by spasms is:", translation:"في الكزاز، أول مجموعة عضلية تصاب بالتشنج غالباً هي:", options:["a) Abdominal muscles","b) Masseter muscles (Jaw)","c) Respiratory muscles","d) Leg muscles"], correct:"b) Masseter muscles (Jaw)", correctTranslation:"عضلات المضغ (الفك)"},
    {text:"Hotness in an inflamed area is caused by:", translation:"سبب ارتفاع حرارة المنطقة الملتهبة هو:", options:["a) Tissue death","b) Increased blood flow (Vasodilation)","c) Nerve irritation","d) Accumulation of pus"], correct:"b) Increased blood flow (Vasodilation)", correctTranslation:"زيادة تدفق الدم بسبب توسع الأوعية"},
    {text:"A solution that has the same osmotic pressure as blood is called:", translation:"المحلول الذي له نفس الضغط الأسموزي للدم يُسمى:", options:["a) Hypotonic","b) Hypertonic","c) Isotonic","d) Hydrotonic"], correct:"c) Isotonic", correctTranslation:"متساوي التوتر (Isotonic)"},
    {text:"Which of the following is a symptom of Hyperkalemia (High Potassium)?", translation:"أي مما يلي من أعراض ارتفاع البوتاسيوم؟", options:["a) Cardiac arrhythmias","b) Increased thirst","c) Muscle tetany","d) Hypertension"], correct:"a) Cardiac arrhythmias", correctTranslation:"اضطراب نظم القلب"},
    {text:"The incubation period of Tetanus usually ranges from:", translation:"فترة حضانة الكزاز عادة تتراوح بين:", options:["a) 1 - 2 days","b) 3 - 21 days","c) 1 - 2 months","d) 24 hours"], correct:"b) 3 - 21 days", correctTranslation:"3 إلى 21 يوماً"},
    {text:"Treatment of an abscess primarily involves:", translation:"العلاج الأساسي للخراج هو:", options:["a) Antibiotics only","b) Hot fomentations only","c) Incision and drainage","d) Cold compresses"], correct:"c) Incision and drainage", correctTranslation:"الشق والتصريف"},
    {text:'"Crepitus" (feeling gas bubbles under the skin) is a sign of:', translation:"الطقطقة الغازية تحت الجلد علامة على:", options:["a) Cellulitis","b) Gas Gangrene","c) Erysipelas","d) Chronic inflammation"], correct:"b) Gas Gangrene", correctTranslation:"الغرغرينا الغازية"},
    {text:"Chronic inflammation is characterized by the presence of:", translation:"يتميز الالتهاب المزمن بوجود:", options:["a) Neutrophils","b) Lymphocytes and Fibrosis","c) Sudden high fever","d) Rapid healing"], correct:"b) Lymphocytes and Fibrosis", correctTranslation:"الخلايا الليمفاوية والتليف"},
    {text:"Severe loss of body water leading to poor skin turgor and dry tongue is:", translation:"فقد شديد لماء الجسم يؤدي لضعف مرونة الجلد وجفاف اللسان يُسمى:", options:["a) Edema","b) Dehydration","c) Water intoxication","d) Hypervolemia"], correct:"b) Dehydration", correctTranslation:"الجفاف (Dehydration)"},
    {text:"The primary extracellular cation (outside the cell) is:", translation:"الكاتيون الرئيسي خارج الخلية هو:", options:["a) Sodium","b) Potassium","c) Magnesium","d) Phosphate"], correct:"a) Sodium", correctTranslation:"الصوديوم"},
    {text:"Septic shock is most commonly caused by:", translation:"صدمة الإنتان تحدث غالباً بسبب:", options:["a) Spinal cord injury","b) Gram-negative bacteria","c) Severe pain","d) Allergic reaction"], correct:"b) Gram-negative bacteria", correctTranslation:"البكتيريا سالبة الجرام"},
    {text:"Trousseau's sign (carpal spasm) is used to detect:", translation:"علامة تروسو (تشنج الرسغ) تُستخدم لاكتشاف:", options:["a) Hypokalemia","b) Hypocalcemia","c) Hypernatremia","d) Hypomagnesemia"], correct:"b) Hypocalcemia", correctTranslation:"نقص كالسيوم الدم"},
    {text:"Inflammation of the lymphatic vessels is called:", translation:"التهاب الأوعية الليمفاوية يُسمى:", options:["a) Lymphadenitis","b) Lymphangitis","c) Lymphedema","d) Phlebitis"], correct:"b) Lymphangitis", correctTranslation:"التهاب الأوعية الليمفاوية"},
    {text:"A major complication of long-term IV fluid therapy is:", translation:"من أهم مضاعفات المحاليل الوريدية طويلة المدة:", options:["a) Thrombophlebitis","b) Tetanus","c) Fractures","d) Gastritis"], correct:"a) Thrombophlebitis", correctTranslation:"التهاب الوريد الخثاري"},
    {text:'The "Golden Hour" refers to the first hour after:', translation:'مصطلح "الساعة الذهبية" يشير لأول ساعة بعد:', options:["a) Infection","b) Trauma/Injury","c) General anesthesia","d) Skin rash"], correct:"b) Trauma/Injury", correctTranslation:"الإصابة/الرضح"},
    {text:"Which of these is an anaerobic infection?", translation:"أي مما يلي عدوى لاهوائية؟", options:["a) Erysipelas","b) Gas Gangrene","c) Boil","d) Tonsillitis"], correct:"b) Gas Gangrene", correctTranslation:"الغرغرينا الغازية"},
    {text:"Normal serum Calcium level is:", translation:"المعدل الطبيعي لكالسيوم المصل:", options:["a) 135-145 mEq/L","b) 9 - 11 mg/dL","c) 3.5-5 mEq/L","d) 100-110 mEq/L"], correct:"b) 9 - 11 mg/dL", correctTranslation:"9 - 11 ملجم/دل"},
    {text:"Inflammation of a lymph node is known as:", translation:"التهاب العقدة الليمفاوية يُعرف بـ:", options:["a) Lymphadenitis","b) Lymphangitis","c) Lymphoma","d) Cellulitis"], correct:"a) Lymphadenitis", correctTranslation:"التهاب العقد الليمفاوية"},
    {text:"Potassium imbalance mainly affects the function of the:", translation:"اختلال البوتاسيوم يؤثر بشكل رئيسي على وظيفة:", options:["a) Liver","b) Heart (Myocardium)","c) Spleen","d) Gallbladder"], correct:"b) Heart (Myocardium)", correctTranslation:"عضلة القلب"},
    {text:'In the inflammatory process, "Tumor" means:', translation:'في عملية الالتهاب، مصطلح "Tumor" يعني:', options:["a) Cancer","b) Swelling","c) Redness","d) Pain"], correct:"b) Swelling", correctTranslation:"التورم"},
    {text:"Which solution is used for emergency volume replacement in shock?", translation:"أي محلول يُستخدم لتعويض حجم الدم الطارئ في الصدمة؟", options:["a) 5% Glucose","b) Ringer's Lactate / Normal Saline","c) Sterile water","d) Half-normal saline"], correct:"b) Ringer's Lactate / Normal Saline", correctTranslation:"محلول رينجر لاكتيت / المحلول الملحي الطبيعي"},
    {text:"The primary cause of death in Tetanus is:", translation:"السبب الرئيسي للوفاة في الكزاز هو:", options:["a) Kidney failure","b) Asphyxia (Respiratory failure)","c) Liver failure","d) Internal bleeding"], correct:"b) Asphyxia (Respiratory failure)", correctTranslation:"الاختناق (فشل تنفسي)"},
    {text:"Erysipelas is a specific type of cellulitis caused by:", translation:"الحمرة (Erysipelas) نوع خاص من التهاب النسيج الخلوي يسببه:", options:["a) Staphylococci","b) Streptococcus pyogenes","c) Clostridium","d) Pneumococci"], correct:"b) Streptococcus pyogenes", correctTranslation:"المكورات العقدية المقيحة"},
    {text:'The main sign of "Water Intoxication" is:', translation:'العلامة الرئيسية لـ"التسمم المائي" هي:', options:["a) Thirst","b) Cerebral edema (Confusion/Coma)","c) Dry skin","d) Dark urine"], correct:"b) Cerebral edema (Confusion/Coma)", correctTranslation:"وذمة دماغية (تشوش/غيبوبة)"},
    {text:"Pain in acute inflammation is caused by:", translation:"سبب الألم في الالتهاب الحاد هو:", options:["a) Low temperature","b) Pressure of exudate on nerve endings","c) Fast heart rate","d) Lack of oxygen"], correct:"b) Pressure of exudate on nerve endings", correctTranslation:"ضغط الإفرازات على النهايات العصبية"},
    {text:"Hypovolemic shock results in:", translation:"صدمة نقص الحجم تؤدي إلى:", options:["a) Bradycardia (slow pulse)","b) Tachycardia (fast pulse)","c) High blood pressure","d) Warm skin"], correct:"b) Tachycardia (fast pulse)", correctTranslation:"تسرع النبض"},
    {text:"Tetanus toxin is called:", translation:"سم الكزاز يُسمى:", options:["a) Endotoxin","b) Exotoxin (Tetanospasmin)","c) Mycotoxin","d) Enterotoxin"], correct:"b) Exotoxin (Tetanospasmin)", correctTranslation:"ذيفان خارجي (تيتانوسبازمين)"},
    {text:"Which electrolyte is critical for nerve impulse transmission?", translation:"أي إلكتروليت ضروري لنقل السيالة العصبية؟", options:["a) Sodium and Potassium","b) Iron","c) Iodine","d) Zinc"], correct:"a) Sodium and Potassium", correctTranslation:"الصوديوم والبوتاسيوم"},
    {text:'A "Sinus" in surgery means:', translation:'مصطلح "الجيب/الناسور الأعمى" في الجراحة يعني:', options:["a) A collection of pus","b) A blind track lined by granulation tissue","c) A connection between two organs","d) A type of tumor"], correct:"b) A blind track lined by granulation tissue", correctTranslation:"مسار أعمى مبطن بنسيج حبيبي"},
    {text:"Metabolic Acidosis can occur due to:", translation:"الحماض الاستقلابي قد يحدث بسبب:", options:["a) Excessive vomiting","b) Severe diarrhea","c) Rapid breathing","d) High altitude"], correct:"b) Severe diarrhea", correctTranslation:"الإسهال الشديد"},
    {text:"The goal of nursing care for a Tetanus patient is:", translation:"هدف التمريض في رعاية مريض الكزاز هو:", options:["a) Preventing spasms and respiratory distress","b) Increasing physical activity","c) Providing a bright, noisy environment","d) Reducing fluid intake"], correct:"a) Preventing spasms and respiratory distress", correctTranslation:"الوقاية من التشنجات وضيق التنفس"},
    {text:"What is the color of the skin in Erysipelas?", translation:"ما لون الجلد في مرض الحمرة؟", options:["a) Pale","b) Blue","c) Bright Red (Rose red)","d) Yellow"], correct:"c) Bright Red (Rose red)", correctTranslation:"أحمر وردي زاهٍ"},
    {text:"Calcium absorption from the gut requires:", translation:"امتصاص الكالسيوم من الأمعاء يحتاج إلى:", options:["a) Vitamin C","b) Vitamin D","c) Vitamin K","d) Vitamin B12"], correct:"b) Vitamin D", correctTranslation:"فيتامين د"},
    {text:"Systemic effects of inflammation include:", translation:"من التأثيرات الجهازية للالتهاب:", options:["a) Fever and Leukocytosis","b) Local swelling only","c) Hair loss","d) Weight gain"], correct:"a) Fever and Leukocytosis", correctTranslation:"الحمى وزيادة كرات الدم البيضاء"},
    {text:"In Gas Gangrene, the surgical treatment is called:", translation:"العلاج الجراحي في الغرغرينا الغازية يُسمى:", options:["a) Incision","b) Debridement (Removing dead tissue)","c) Biopsy","d) Simple dressing"], correct:"b) Debridement (Removing dead tissue)", correctTranslation:"التنضير (إزالة الأنسجة الميتة)"},
    {text:"Pus consists of:", translation:"يتكون الصديد من:", options:["a) Blood and water only","b) Dead WBCs, bacteria, and necrotic tissue","c) Fresh oxygenated blood","d) Lymphatic fluid only"], correct:"b) Dead WBCs, bacteria, and necrotic tissue", correctTranslation:"كرات دم بيضاء ميتة وبكتيريا وأنسجة نخرية"},
    {text:"Which of the following indicates a positive response to fluid therapy in shock?", translation:"أي مما يلي يدل على استجابة جيدة لعلاج السوائل في الصدمة؟", options:["a) Increased urine output","b) Increased heart rate","c) Decreased blood pressure","d) Cold extremities"], correct:"a) Increased urine output", correctTranslation:"زيادة كمية البول"}
  ],

  truefalse: [
    {text:"Acute inflammation is characterized by a sudden onset and short duration.", translation:"يتميز الالتهاب الحاد ببداية مفاجئة ومدة قصيرة.", correct:true},
    {text:"Chronic inflammation usually ends with complete healing without leaving any scars.", translation:"عادة ينتهي الالتهاب المزمن بشفاء كامل دون أي ندبات.", correct:false},
    {text:"Redness in inflammation is caused by a decrease in blood flow to the affected area.", translation:"الاحمرار في الالتهاب سببه نقص تدفق الدم للمنطقة المصابة.", correct:false},
    {text:"A boil (Furuncle) is a localized clinical form of acute suppurative inflammation.", translation:"الدمل (Furuncle) صورة سريرية موضعية من الالتهاب القيحي الحاد.", correct:true},
    {text:"Cellulitis is a localized inflammation with a clear boundary.", translation:"التهاب النسيج الخلوي التهاب موضعي محدد الحدود بوضوح.", correct:false},
    {text:"A carbuncle is more common in diabetic patients.", translation:"الجمرة الجلدية أكثر شيوعاً لدى مرضى السكري.", correct:true},
    {text:"Hot fomentations are used to treat early stages of acute inflammation.", translation:"الكمادات الساخنة تُستخدم في المراحل المبكرة من الالتهاب الحاد.", correct:false},
    {text:"Tetanus is caused by an aerobic bacterium called Clostridium tetani.", translation:"الكزاز يسببه ميكروب هوائي يُسمى المطثية الكزازية.", correct:false},
    {text:"The main sign of Tetanus is muscle spasms, starting with the jaw muscles.", translation:"العلامة الرئيسية للكزاز تشنج العضلات بدءاً من عضلات الفك.", correct:true},
    {text:"Gas gangrene is caused by anaerobic bacteria that produce gas in the tissues.", translation:"الغرغرينا الغازية تسببها بكتيريا لاهوائية تنتج غازاً بالأنسجة.", correct:true},
    {text:"Crepitus is a characteristic sign of gas gangrene.", translation:"الطقطقة الغازية علامة مميزة للغرغرينا الغازية.", correct:true},
    {text:"Sodium (Na) is the primary cation in the intracellular fluid (ICF).", translation:"الصوديوم هو الكاتيون الرئيسي داخل الخلايا.", correct:false},
    {text:"Potassium (K) is essential for the electrical activity of the heart.", translation:"البوتاسيوم ضروري للنشاط الكهربائي للقلب.", correct:true},
    {text:"The normal range of serum potassium is 3.5 to 5.0 mEq/L.", translation:"المعدل الطبيعي لبوتاسيوم المصل 3.5 - 5.0 ملي مكافئ/لتر.", correct:true},
    {text:"Hypokalemia means an increase in the level of potassium in the blood.", translation:"نقص بوتاسيوم الدم يعني ارتفاع مستوى البوتاسيوم بالدم.", correct:false},
    {text:"Hypernatremia can be caused by excessive water loss or high sodium intake.", translation:"ارتفاع الصوديوم قد يحدث بفقد مفرط للماء أو زيادة تناول الصوديوم.", correct:true},
    {text:"Edema is an accumulation of excess fluid in the interstitial spaces.", translation:"الوذمة تجمع سوائل زائدة في الحيز الخِلالي.", correct:true},
    {text:"Isotonic solutions have the same osmotic pressure as body fluids.", translation:"المحاليل متساوية التوتر لها نفس الضغط الأسموزي لسوائل الجسم.", correct:true},
    {text:"0.9% Normal Saline is considered a hypotonic solution.", translation:"المحلول الملحي 0.9% يُعتبر محلولاً منخفض التوتر.", correct:false},
    {text:"Metabolic Acidosis occurs when there is a loss of bicarbonate from the body.", translation:"الحماض الاستقلابي يحدث عند فقد البيكربونات من الجسم.", correct:true},
    {text:"Shock is a state of inadequate tissue perfusion.", translation:"الصدمة حالة قصور في تروية الأنسجة.", correct:true},
    {text:"Hypovolemic shock is caused by a severe decrease in blood volume.", translation:"صدمة نقص الحجم سببها انخفاض شديد بحجم الدم.", correct:true},
    {text:"In early shock, the blood pressure usually rises significantly.", translation:"في المرحلة المبكرة من الصدمة يرتفع ضغط الدم بشكل ملحوظ.", correct:false},
    {text:"Septic shock is caused by a massive bacterial infection in the blood.", translation:"صدمة الإنتان سببها عدوى بكتيرية شديدة بالدم.", correct:true},
    {text:"Anaphylactic shock is a severe allergic reaction.", translation:"الصدمة التأقية هي رد فعل تحسسي شديد.", correct:true},
    {text:"Specific inflammation includes diseases like Tuberculosis and Syphilis.", translation:"الالتهاب النوعي يشمل أمراضاً مثل السل والزهري.", correct:true},
    {text:"Pus is composed of dead white blood cells, bacteria, and necrotic tissue.", translation:"يتكون الصديد من كرات دم بيضاء ميتة وبكتيريا وأنسجة نخرية.", correct:true},
    {text:"An abscess must be treated with incision and drainage once it fluctuates.", translation:"يجب علاج الخراج بالشق والتصريف بمجرد ظهور علامة التموج.", correct:true},
    {text:"Erysipelas is a type of cellulitis caused by Streptococci.", translation:"الحمرة نوع من التهاب النسيج الخلوي تسببه المكورات العقدية.", correct:true},
    {text:"Tetanus can be transmitted from one person to another (communicable).", translation:"الكزاز مرض معدٍ ينتقل من شخص لآخر.", correct:false},
    {text:'The "Sardonic Smile" is a sign of advanced Tetanus infection.', translation:'"الابتسامة الساخرة" علامة على تقدم عدوى الكزاز.', correct:true},
    {text:"Hyperkalemia (high potassium) can lead to sudden cardiac arrest.", translation:"ارتفاع البوتاسيوم قد يؤدي إلى توقف مفاجئ للقلب.", correct:true},
    {text:"Calcium is necessary for blood coagulation and bone health.", translation:"الكالسيوم ضروري لتخثر الدم وصحة العظام.", correct:true},
    {text:"Chvostek's sign is an indicator of Hypocalcemia.", translation:"علامة شفوستيك مؤشر على نقص كالسيوم الدم.", correct:true},
    {text:"Dehydration leads to increased skin turgor and moist tongue.", translation:"الجفاف يؤدي لزيادة مرونة الجلد ورطوبة اللسان.", correct:false},
    {text:"5% Dextrose in water is initially isotonic but becomes hypotonic in the body.", translation:"محلول الجلوكوز 5% متساوي التوتر مبدئياً ويصبح منخفض التوتر بالجسم.", correct:true},
    {text:"Thrombophlebitis is a common complication of intravenous therapy.", translation:"التهاب الوريد الخثاري مضاعفة شائعة للعلاج الوريدي.", correct:true},
    {text:"Toxemia is the presence of bacteria only in the bloodstream.", translation:"التسمم الدموي يعني وجود البكتيريا فقط في مجرى الدم.", correct:false},
    {text:"Lymphangitis is the inflammation of the lymph nodes.", translation:"التهاب الأوعية الليمفاوية هو التهاب العقد الليمفاوية.", correct:false},
    {text:"Fever and leukocytosis are systemic signs of inflammation.", translation:"الحمى وزيادة الكريات البيضاء علامتان جهازيتان للالتهاب.", correct:true},
    {text:"Chronic inflammation can lead to the formation of a granuloma.", translation:"الالتهاب المزمن قد يؤدي لتكوّن الورم الحبيبي.", correct:true},
    {text:"Gas gangrene requires urgent surgical debridement of dead tissue.", translation:"تتطلب الغرغرينا الغازية تنضيراً جراحياً عاجلاً للأنسجة الميتة.", correct:true},
    {text:"The incubation period for Tetanus is always 24 hours.", translation:"فترة حضانة الكزاز دائماً 24 ساعة.", correct:false},
    {text:"Passive immunity for Tetanus is provided by the Tetanus Toxoid vaccine.", translation:"المناعة السلبية ضد الكزاز يوفرها لقاح الذوفان الكزازي.", correct:false},
    {text:"Fluid volume deficit can lead to a rapid, weak pulse (tachycardia).", translation:"نقص حجم السوائل قد يؤدي لنبض سريع وضعيف.", correct:true},
    {text:"Normal saline (0.9% NaCl) is used to treat hypovolemic shock.", translation:"المحلول الملحي 0.9% يُستخدم لعلاج صدمة نقص الحجم.", correct:true},
    {text:"Hyperventilation can lead to Respiratory Alkalosis.", translation:"فرط التهوية قد يؤدي إلى القلاء التنفسي.", correct:true},
    {text:"A sinus is an abnormal track connecting two epithelial surfaces.", translation:"الجيب مسار غير طبيعي يصل بين سطحين ظهاريين.", correct:false},
    {text:"Osmosis is the movement of solutes from high to low concentration.", translation:"التناضح هو انتقال المذابات من التركيز المرتفع للمنخفض.", correct:false},
    {text:"Nursing care for a Tetanus patient requires a quiet and dark room.", translation:"رعاية مريض الكزاز تتطلب غرفة هادئة ومظلمة.", correct:true}
  ],

  complete: [
    {text:"The five cardinal signs of acute inflammation are redness, hotness, swelling, pain, and ____.", translation:"العلامات الخمس الأساسية للالتهاب الحاد: احمرار، حرارة، تورم، ألم، و ____.", completion:"Loss of function", completionTranslation:"فقدان الوظيفة"},
    {text:"____ is a localized collection of pus in a cavity formed by tissue destruction.", translation:"____ تجمع صديد موضعي بتجويف ناتج عن تدمير الأنسجة.", completion:"Abscess", completionTranslation:"الخراج"},
    {text:"The primary extracellular cation responsible for osmotic pressure is ____.", translation:"الكاتيون الرئيسي خارج الخلية المسؤول عن الضغط الأسموزي هو ____.", completion:"Sodium (Na+)", completionTranslation:"الصوديوم"},
    {text:"____ is a diffuse, spreading inflammation of the subcutaneous connective tissue.", translation:"____ التهاب منتشر بالنسيج الضام تحت الجلد.", completion:"Cellulitis", completionTranslation:"التهاب النسيج الخلوي"},
    {text:"The normal serum level of Potassium (K+) is ___ to ___ mEq/L.", translation:"المعدل الطبيعي لبوتاسيوم المصل من ___ إلى ___ ملي مكافئ/لتر.", completion:"3.5 – 5.0", completionTranslation:"3.5 - 5.0"},
    {text:"Tetanus is caused by an anaerobic, spore-forming bacterium called ____.", translation:"الكزاز يسببه ميكروب لاهوائي مكوّن للأبواغ يُسمى ____.", completion:"Clostridium tetani", completionTranslation:"المطثية الكزازية"},
    {text:'The characteristic facial expression in Tetanus known as "Sardonic Smile" is called ____.', translation:'التعبير الوجهي المميز في الكزاز "الابتسامة الساخرة" يُسمى علمياً ____.', completion:"Risus Sardonicus", completionTranslation:"العته التشنجي الساخر"},
    {text:"____ gangrene is caused by gas-producing organisms like Clostridium Welchii.", translation:"الغرغرينا ____ تسببها ميكروبات منتجة للغاز مثل المطثية الحاطمة.", completion:"Gas", completionTranslation:"الغازية"},
    {text:"The movement of water through a semi-permeable membrane is called ____.", translation:"انتقال الماء عبر غشاء شبه منفذ يُسمى ____.", completion:"Osmosis", completionTranslation:"التناضح"},
    {text:"A cluster of interconnected boils with multiple drainage points is a ____.", translation:"تجمع دمامل متصلة بفتحات تصريف متعددة يُسمى ____.", completion:"Carbuncle", completionTranslation:"الجمرة الجلدية"},
    {text:"____ shock occurs due to severe loss of blood, plasma, or body fluids.", translation:"صدمة ____ تحدث بسبب فقد شديد للدم أو البلازما أو سوائل الجسم.", completion:"Hypovolemic", completionTranslation:"نقص الحجم"},
    {text:"The most common cause of septic shock is ____ bacteria.", translation:"أشيع سبب لصدمة الإنتان بكتيريا ____.", completion:"Gram-negative", completionTranslation:"سالبة الجرام"},
    {text:"High concentration of sodium in the blood is termed ____.", translation:"ارتفاع تركيز الصوديوم بالدم يُسمى ____.", completion:"Hypernatremia", completionTranslation:"فرط صوديوم الدم"},
    {text:"____ is the main intracellular cation.", translation:"____ هو الكاتيون الرئيسي داخل الخلية.", completion:"Potassium (K+)", completionTranslation:"البوتاسيوم"},
    {text:"Chronic inflammation is characterized by the presence of ___ and ___.", translation:"يتميز الالتهاب المزمن بوجود ___ و ___.", completion:"Lymphocytes / Fibrosis", completionTranslation:"الخلايا الليمفاوية / التليف"},
    {text:"The inability to open the mouth in Tetanus due to muscle spasm is called ____.", translation:"عدم القدرة على فتح الفم في الكزاز بسبب التشنج يُسمى ____.", completion:"Trismus (Lockjaw)", completionTranslation:"التشنج الفكي (قفل الفك)"},
    {text:"____ solutions have a lower osmotic pressure than blood.", translation:"المحاليل ____ لها ضغط أسموزي أقل من الدم.", completion:"Hypotonic", completionTranslation:"منخفضة التوتر"},
    {text:"Chvostek's sign and Trousseau's sign are used to diagnose ____.", translation:"علامتا شفوستيك وتروسو تُستخدمان لتشخيص ____.", completion:"Hypocalcemia", completionTranslation:"نقص كالسيوم الدم"},
    {text:"Inflammation of the lymphatic vessels is known as ____.", translation:"التهاب الأوعية الليمفاوية يُعرف بـ ____.", completion:"Lymphangitis", completionTranslation:"التهاب الأوعية الليمفاوية"},
    {text:"The primary treatment for a fluctuant abscess is ___ and ___.", translation:"العلاج الأساسي للخراج المتموج هو ___ و ___.", completion:"Incision / Drainage", completionTranslation:"الشق والتصريف"},
    {text:"____ is a serious condition where bacteria and their toxins circulate in the blood.", translation:"____ حالة خطيرة تسري فيها البكتيريا وسمومها بالدم.", completion:"Septicemia (or Toxemia)", completionTranslation:"تجرثم الدم / التسمم الدموي"},
    {text:'The "Golden Hour" is the critical first hour following ____.', translation:'"الساعة الذهبية" هي أول ساعة حرجة بعد ____.', completion:"Trauma (Injury)", completionTranslation:"الإصابة"},
    {text:"Normal saline (0.9% NaCl) is an ____ solution.", translation:"المحلول الملحي 0.9% محلول ____.", completion:"Isotonic", completionTranslation:"متساوي التوتر"},
    {text:"____ is the death of body tissue due to a lack of blood supply.", translation:"____ موت النسيج بسبب نقص التروية الدموية.", completion:"Gangrene", completionTranslation:"الغرغرينا"},
    {text:"Respiratory ____ occurs due to hyperventilation and loss of CO2.", translation:"____ التنفسي يحدث بسبب فرط التهوية وفقد ثاني أكسيد الكربون.", completion:"Alkalosis", completionTranslation:"القلاء"},
    {text:"The incubation period of Tetanus usually lasts from ___ to ___ days.", translation:"تستمر فترة حضانة الكزاز من ___ إلى ___ يوماً.", completion:"3 – 21", completionTranslation:"3 - 21 يوماً"},
    {text:"____ is a type of cellulitis caused by Streptococcus pyogenes, characterized by a rose-red color.", translation:"____ نوع من التهاب النسيج الخلوي تسببه العقديات المقيحة ويتميز بلون وردي أحمر.", completion:"Erysipelas", completionTranslation:"الحمرة"},
    {text:"Signs of dehydration include dry tongue, sunken eyes, and poor ____.", translation:"من علامات الجفاف جفاف اللسان وغؤور العينين وضعف ____.", completion:"Skin turgor", completionTranslation:"مرونة الجلد"},
    {text:"To prevent Tetanus in a wounded patient, we give ____ for immediate passive immunity.", translation:"للوقاية من الكزاز في المريض المصاب نُعطي ____ لمناعة سلبية فورية.", completion:"A.T.S (Antitetanic Serum)", completionTranslation:"مصل مضاد الكزاز"},
    {text:"Excessive administration of IV fluids can lead to ____.", translation:"الإفراط في إعطاء المحاليل الوريدية قد يؤدي إلى ____.", completion:"Pulmonary edema (Fluid overload)", completionTranslation:"وذمة رئوية (فرط الحمل السائلي)"},
    {text:"Potassium imbalance primarily affects the ____ muscle.", translation:"اختلال البوتاسيوم يؤثر بشكل رئيسي على عضلة ____.", completion:"Heart (Myocardium)", completionTranslation:"القلب"},
    {text:"An abnormal track connecting two epithelial surfaces is called a ____.", translation:"مسار غير طبيعي يصل بين سطحين ظهاريين يُسمى ____.", completion:"Fistula", completionTranslation:"الناسور"},
    {text:"The process of removing dead or infected tissue from a wound is ____.", translation:"إزالة الأنسجة الميتة أو المصابة من الجرح تُسمى ____.", completion:"Debridement", completionTranslation:"التنضير"},
    {text:"____ is the primary organ responsible for regulating fluid and electrolyte balance.", translation:"____ العضو الرئيسي المسؤول عن تنظيم توازن السوائل والكهارل.", completion:"Kidney", completionTranslation:"الكلية"},
    {text:"Low blood calcium levels can cause muscle spasms known as ____.", translation:"انخفاض كالسيوم الدم قد يسبب تشنجات عضلية تُعرف بـ ____.", completion:"Tetany", completionTranslation:"التكزز"},
    {text:"In inflammation, the term for redness is ___ and for swelling is ___.", translation:"في الالتهاب، مصطلح الاحمرار ___ ومصطلح التورم ___.", completion:"Rubor / Tumor", completionTranslation:"الاحمرار / التورم"},
    {text:"Metabolic ____ can result from severe prolonged diarrhea.", translation:"____ الاستقلابي قد ينتج عن إسهال شديد ومطوّل.", completion:"Acidosis", completionTranslation:"الحماض"},
    {text:"The state of circulatory collapse where tissue perfusion is inadequate is ____.", translation:"حالة انهيار الدورة الدموية مع قصور تروية الأنسجة تُسمى ____.", completion:"Shock", completionTranslation:"الصدمة"},
    {text:"____ immunity is provided by the Tetanus Toxoid vaccine.", translation:"مناعة ____ يوفرها لقاح الذوفان الكزازي.", completion:"Active", completionTranslation:"فعالة (نشطة)"},
    {text:"Pus consists of dead ____, bacteria, and necrotic tissue debris.", translation:"يتكون الصديد من ____ ميتة وبكتيريا وأنسجة نخرية متحللة.", completion:"White Blood Cells (Leukocytes)", completionTranslation:"كرات الدم البيضاء"},
    {text:"____ shock is caused by a severe, life-threatening allergic reaction.", translation:"صدمة ____ سببها رد فعل تحسسي شديد يهدد الحياة.", completion:"Anaphylactic", completionTranslation:"تأقية"},
    {text:"Feeling gas bubbles under the skin in gas gangrene is known as ____.", translation:"الإحساس بفقاعات غاز تحت الجلد في الغرغرينا الغازية يُعرف بـ ____.", completion:"Crepitus", completionTranslation:"الطقطقة الغازية"},
    {text:"The first muscle group usually affected in Tetanus is the ____ muscles.", translation:"أول مجموعة عضلية تُصاب في الكزاز غالباً عضلات ____.", completion:"Masseter (Jaw)", completionTranslation:"المضغ (الفك)"},
    {text:"Hypokalemia can be caused by the excessive use of ____ drugs.", translation:"نقص بوتاسيوم الدم قد يحدث بسبب الإفراط في أدوية ____.", completion:"Diuretic", completionTranslation:"مدرة للبول"},
    {text:"A solution of 5% Dextrose in water is initially ____.", translation:"محلول الجلوكوز 5% يكون مبدئياً ____.", completion:"Isotonic", completionTranslation:"متساوي التوتر"},
    {text:"The main systemic signs of inflammation are ___ and ___.", translation:"أهم العلامات الجهازية للالتهاب هي ___ و ___.", completion:"Fever / Leukocytosis", completionTranslation:"الحمى / زيادة الكريات البيضاء"},
    {text:"Severe vomiting can lead to Metabolic ____.", translation:"القيء الشديد قد يؤدي إلى ____ الاستقلابي.", completion:"Alkalosis", completionTranslation:"القلاء"},
    {text:"____ is the inflammation of a lymph node.", translation:"____ التهاب العقدة الليمفاوية.", completion:"Lymphadenitis", completionTranslation:"التهاب العقد الليمفاوية"},
    {text:"The hormone that regulates sodium reabsorption in the kidney is ____.", translation:"الهرمون المنظم لإعادة امتصاص الصوديوم بالكلية هو ____.", completion:"Aldosterone", completionTranslation:"الألدوستيرون"},
    {text:"Nursing care for Tetanus involves keeping the patient in a ___ and ___ room.", translation:"رعاية مريض الكزاز تتطلب وضعه بغرفة ___ و ___.", completion:"Quiet / Dark", completionTranslation:"هادئة / مظلمة"}
  ],

  definitions: [
    {text:"A local response of living mammalian tissues to injury.", translation:"استجابة موضعية للأنسجة الحية تجاه الإصابة.", answer:"Inflammation", answerTranslation:"الالتهاب"},
    {text:"A localized collection of pus in a cavity formed by the disintegration of tissues.", translation:"تجمع صديد موضعي بتجويف ناتج عن تحلل الأنسجة.", answer:"Abscess", answerTranslation:"الخراج"},
    {text:"A diffuse, spreading inflammation of the subcutaneous connective tissue.", translation:"التهاب منتشر بالنسيج الضام تحت الجلد.", answer:"Cellulitis", answerTranslation:"التهاب النسيج الخلوي"},
    {text:"A cluster of boils connected together under the skin with multiple openings.", translation:"تجمع دمامل متصلة تحت الجلد بفتحات متعددة.", answer:"Carbuncle", answerTranslation:"الجمرة الجلدية"},
    {text:"Death of body tissue due to loss of blood supply or bacterial infection.", translation:"موت النسيج بسبب انقطاع التروية أو عدوى بكتيرية.", answer:"Gangrene", answerTranslation:"الغرغرينا"},
    {text:"An acute infectious disease caused by Clostridium tetani affecting the nervous system.", translation:"مرض معدٍ حاد يصيب الجهاز العصبي تسببه المطثية الكزازية.", answer:"Tetanus", answerTranslation:"الكزاز"},
    {text:"A specific type of gangrene caused by anaerobic gas-forming bacteria.", translation:"نوع خاص من الغرغرينا تسببه بكتيريا لاهوائية منتجة للغاز.", answer:"Gas Gangrene", answerTranslation:"الغرغرينا الغازية"},
    {text:"The movement of water from an area of low solute concentration to high concentration.", translation:"انتقال الماء من تركيز مذاب منخفض إلى مرتفع.", answer:"Osmosis", answerTranslation:"التناضح"},
    {text:"The primary cation in the extracellular fluid (ECF).", translation:"الكاتيون الرئيسي في السائل خارج الخلوي.", answer:"Sodium (Na+)", answerTranslation:"الصوديوم"},
    {text:"The primary cation in the intracellular fluid (ICF).", translation:"الكاتيون الرئيسي في السائل داخل الخلوي.", answer:"Potassium (K+)", answerTranslation:"البوتاسيوم"},
    {text:"A state of inadequate tissue perfusion and circulatory failure.", translation:"حالة قصور تروية الأنسجة وانهيار الدورة الدموية.", answer:"Shock", answerTranslation:"الصدمة"},
    {text:"A severe, life-threatening allergic reaction.", translation:"رد فعل تحسسي شديد يهدد الحياة.", answer:"Anaphylactic Shock", answerTranslation:"الصدمة التأقية"},
    {text:"High concentration of potassium in the blood.", translation:"ارتفاع تركيز البوتاسيوم بالدم.", answer:"Hyperkalemia", answerTranslation:"فرط بوتاسيوم الدم"},
    {text:"Low concentration of sodium in the blood.", translation:"انخفاض تركيز الصوديوم بالدم.", answer:"Hyponatremia", answerTranslation:"نقص صوديوم الدم"},
    {text:"An abnormal track connecting two epithelial-lined surfaces.", translation:"مسار غير طبيعي يصل بين سطحين مبطنين بالظهارة.", answer:"Fistula", answerTranslation:"الناسور"},
    {text:"A blind track lined by granulation tissue that opens on an epithelial surface.", translation:"مسار أعمى مبطن بنسيج حبيبي يفتح على سطح ظهاري.", answer:"Sinus", answerTranslation:"الجيب (السينوس)"},
    {text:"The fluid that leaks out of blood vessels during inflammation, rich in proteins.", translation:"السائل المتسرب من الأوعية الدموية أثناء الالتهاب والغني بالبروتينات.", answer:"Exudate", answerTranslation:"الإفراز الالتهابي"},
    {text:"Inflammation of the lymphatic vessels.", translation:"التهاب الأوعية الليمفاوية.", answer:"Lymphangitis", answerTranslation:"التهاب الأوعية الليمفاوية"},
    {text:"Inflammation of the lymph node.", translation:"التهاب العقدة الليمفاوية.", answer:"Lymphadenitis", answerTranslation:"التهاب العقد الليمفاوية"},
    {text:"A sign of Tetanus characterized by a fixed, sardonic grin.", translation:"علامة كزازية تتميز بابتسامة ساخرة ثابتة.", answer:"Risus Sardonicus", answerTranslation:"العته التشنجي الساخر"},
    {text:"Inability to open the mouth due to muscle spasms in Tetanus.", translation:"عدم القدرة على فتح الفم بسبب تشنج العضلات في الكزاز.", answer:"Trismus (Lockjaw)", answerTranslation:"التشنج الفكي"},
    {text:"A state where bacteria and their toxins circulate and multiply in the blood.", translation:"حالة تسري وتتكاثر فيها البكتيريا وسمومها بالدم.", answer:"Septicemia", answerTranslation:"تجرثم الدم"},
    {text:"The type of inflammation caused by Mycobacterium Tuberculosis.", translation:"نوع الالتهاب الذي تسببه عصية السل.", answer:"Specific Inflammation", answerTranslation:"الالتهاب النوعي"},
    {text:"A clinical sign of hypocalcemia involving facial muscle twitching when tapped.", translation:"علامة سريرية لنقص كالسيوم الدم تتمثل بارتعاش عضلات الوجه عند النقر.", answer:"Chvostek's sign", answerTranslation:"علامة شفوستيك"},
    {text:"Carpal spasm induced by inflating a blood pressure cuff, indicating hypocalcemia.", translation:"تشنج الرسغ الناتج عن نفخ رباط ضغط الدم، ويدل على نقص كالسيوم الدم.", answer:"Trousseau's sign", answerTranslation:"علامة تروسو"},
    {text:"Solutions that have the same osmotic pressure as plasma (e.g., 0.9% NaCl).", translation:"محاليل لها نفس الضغط الأسموزي للبلازما (مثل الملحي 0.9%).", answer:"Isotonic solutions", answerTranslation:"محاليل متساوية التوتر"},
    {text:"Excessive loss of body water leading to dry mucous membranes.", translation:"فقد مفرط لماء الجسم يؤدي لجفاف الأغشية المخاطية.", answer:"Dehydration", answerTranslation:"الجفاف"},
    {text:"A condition of excess fluid in the interstitial spaces (swelling).", translation:"حالة فرط سوائل بالحيز الخِلالي (تورم).", answer:"Edema", answerTranslation:"الوذمة"},
    {text:"Inflammation of a vein, often caused by IV therapy.", translation:"التهاب الوريد، غالباً بسبب العلاج الوريدي.", answer:"Phlebitis / Thrombophlebitis", answerTranslation:"التهاب الوريد / التهاب الوريد الخثاري"},
    {text:"The process of removing dead or infected tissue from a wound.", translation:"إزالة الأنسجة الميتة أو المصابة من الجرح.", answer:"Debridement", answerTranslation:"التنضير"},
    {text:"Bacteria that can live and grow without oxygen.", translation:"بكتيريا تستطيع العيش والنمو دون أكسجين.", answer:"Anaerobes", answerTranslation:"اللاهوائيات"},
    {text:"The first stage of shock where the body tries to maintain blood pressure.", translation:"المرحلة الأولى من الصدمة حيث يحاول الجسم الحفاظ على ضغط الدم.", answer:"Compensated Shock", answerTranslation:"الصدمة المعوَّضة"},
    {text:"Shock caused by severe infection and toxins.", translation:"صدمة سببها عدوى شديدة وسموم.", answer:"Septic Shock", answerTranslation:"صدمة الإنتان"},
    {text:"A substance produced by bacteria that causes harmful effects (e.g., Tetanospasmin).", translation:"مادة تفرزها البكتيريا وتسبب تأثيرات ضارة (مثل التيتانوسبازمين).", answer:"Toxin", answerTranslation:"الذيفان (السم الميكروبي)"},
    {text:"Permanent death of tissue that becomes black and cold.", translation:"موت دائم للنسيج يصبح فيه أسود وبارداً.", answer:"Necrosis", answerTranslation:"النخر"},
    {text:"The feeling of gas bubbles under the skin in gas gangrene.", translation:"الشعور بفقاعات غاز تحت الجلد في الغرغرينا الغازية.", answer:"Crepitus", answerTranslation:"الطقطقة الغازية"},
    {text:"Small, localized painful inflammation of a hair follicle or sebaceous gland.", translation:"التهاب موضعي مؤلم صغير في بصيلة شعر أو غدة دهنية.", answer:"Boil (Furuncle)", answerTranslation:"الدمل"},
    {text:"A sharp, high-pitched sound heard during inspiration in Tetanus patients.", translation:"صوت حاد عالي النبرة يُسمع أثناء الشهيق لدى مرضى الكزاز.", answer:"Stridor", answerTranslation:"الصرير التنفسي"},
    {text:"The interval between the entry of the bacteria and the appearance of symptoms.", translation:"الفترة بين دخول البكتيريا وظهور الأعراض.", answer:"Incubation period", answerTranslation:"فترة الحضانة"},
    {text:"A type of immunity provided by injecting Tetanus Antitoxin (ATS).", translation:"نوع مناعة يتم توفيره بحقن مصل مضاد الكزاز.", answer:"Passive Immunity", answerTranslation:"المناعة السلبية"},
    {text:"A type of immunity provided by the Tetanus Toxoid vaccine.", translation:"نوع مناعة يوفره لقاح الذوفان الكزازي.", answer:"Active Immunity", answerTranslation:"المناعة الفعالة"},
    {text:"A serious condition caused by rapid infusion of IV fluids leading to lung congestion.", translation:"حالة خطيرة سببها سرعة تسريب المحاليل الوريدية مؤدية لاحتقان رئوي.", answer:"Pulmonary Edema / Fluid Overload", answerTranslation:"الوذمة الرئوية / فرط الحمل السائلي"},
    {text:"The electrolyte responsible for muscle contraction and nerve impulses.", translation:"الإلكتروليت المسؤول عن انقباض العضلات والسيالة العصبية.", answer:"Electrolytes", answerTranslation:"الشوارد (الإلكتروليتات)"},
    {text:"A pH imbalance caused by excessive loss of CO2 through rapid breathing.", translation:"اختلال حموضة الدم بسبب فقد مفرط لثاني أكسيد الكربون عبر التنفس السريع.", answer:"Respiratory Alkalosis", answerTranslation:"القلاء التنفسي"},
    {text:"A pH imbalance caused by the accumulation of acids or loss of bicarbonate.", translation:"اختلال حموضة الدم بسبب تراكم الأحماض أو فقد البيكربونات.", answer:"Metabolic Acidosis", answerTranslation:"الحماض الاستقلابي"},
    {text:"The localized redness of the skin in inflammation.", translation:"الاحمرار الموضعي للجلد في الالتهاب.", answer:"Rubor (Redness)", answerTranslation:"الاحمرار"},
    {text:"The localized heat or warmth in an inflamed area.", translation:"ارتفاع الحرارة الموضعي بالمنطقة الملتهبة.", answer:"Calor (Heat)", answerTranslation:"الحرارة"},
    {text:"The localized swelling in an inflamed area.", translation:"التورم الموضعي بالمنطقة الملتهبة.", answer:"Tumor (Swelling)", answerTranslation:"التورم"},
    {text:"A localized collection of pus in a pre-existing body cavity (e.g., Pleura).", translation:"تجمع صديد موضعي بتجويف جسدي موجود مسبقاً (مثل الجنبة).", answer:"Empyema", answerTranslation:"الدُّبيلة (تقيح التجويف)"},
    {text:'The "Golden Period" for treating shock and trauma to prevent death.', translation:'"الفترة الذهبية" لعلاج الصدمة والرضح لمنع الوفاة.', answer:"Golden Hour", answerTranslation:"الساعة الذهبية"}
  ],

  explain: [
    {text:"Define Inflammation.", translation:"عرّف الالتهاب.", answer:"A local physiological response of living tissues to injury or irritant.", answerTranslation:"استجابة فسيولوجية موضعية للأنسجة الحية تجاه الإصابة أو المهيّج."},
    {text:"List the 5 cardinal (local) signs of acute inflammation.", translation:"اذكر العلامات الخمس الأساسية (الموضعية) للالتهاب الحاد.", answer:"Redness (Rubor), Hotness (Calor), Swelling (Tumor), Pain (Dolor), and Loss of function.", answerTranslation:"الاحمرار، الحرارة، التورم، الألم، وفقدان الوظيفة."},
    {text:"What is an Abscess?", translation:"ما هو الخراج؟", answer:"A localized collection of pus in a cavity formed by tissue disintegration.", answerTranslation:"تجمع صديد موضعي بتجويف ناتج عن تحلل الأنسجة."},
    {text:"Define Cellulitis.", translation:"عرّف التهاب النسيج الخلوي.", answer:"A diffuse, spreading acute inflammation of the subcutaneous connective tissue.", answerTranslation:"التهاب حاد منتشر بالنسيج الضام تحت الجلد."},
    {text:"Mention the causative organism of Tetanus.", translation:"اذكر الميكروب المسبب للكزاز.", answer:"Clostridium tetani (Anaerobic, Gram-positive bacilli).", answerTranslation:"المطثية الكزازية (عصيات لاهوائية موجبة الجرام)."},
    {text:"What are the clinical stages of Tetanus?", translation:"ما هي المراحل السريرية للكزاز؟", answer:"Incubation period, Period of onset (Trismus), and Period of spasms.", answerTranslation:"فترة الحضانة، فترة البداية (التشنج الفكي)، وفترة التشنجات."},
    {text:'Describe the "Sardonic Smile" (Risus Sardonicus).', translation:'صف "الابتسامة الساخرة".', answer:"A characteristic grin caused by spasms of the facial muscles in Tetanus.", answerTranslation:"تعبير وجهي مميز ناتج عن تشنج عضلات الوجه في مرض الكزاز."},
    {text:"Define Gas Gangrene.", translation:"عرّف الغرغرينا الغازية.", answer:"Life-threatening infection of muscle caused by anaerobic bacteria (Clostridium Welchii) producing gas.", answerTranslation:"عدوى عضلية مهددة للحياة تسببها بكتيريا لاهوائية (المطثية الحاطمة) تنتج غازاً."},
    {text:'What is the "Crepitus" sign in Gas Gangrene?', translation:'ما هي علامة "الطقطقة الغازية" في الغرغرينا الغازية؟', answer:"Crackling sensation under the skin due to gas bubbles in the tissues.", answerTranslation:"إحساس بالطقطقة تحت الجلد بسبب فقاعات الغاز بالأنسجة."},
    {text:"Define Shock.", translation:"عرّف الصدمة.", answer:"Acute circulatory failure leading to inadequate tissue perfusion and cellular hypoxia.", answerTranslation:"فشل حاد بالدورة الدموية يؤدي لقصور تروية الأنسجة ونقص أكسجة الخلايا."},
    {text:"List the three main types of Shock.", translation:"اذكر الأنواع الرئيسية الثلاثة للصدمة.", answer:"Hypovolemic shock, Cardiogenic shock, and Distributive shock (Septic, Neurogenic, Anaphylactic).", answerTranslation:"صدمة نقص الحجم، الصدمة القلبية، وصدمة التوزيع (الإنتانية، العصبية، التأقية)."},
    {text:"What is Hypovolemic Shock?", translation:"ما هي صدمة نقص الحجم؟", answer:"Shock caused by a decrease in blood volume (hemorrhage, dehydration, or burns).", answerTranslation:"صدمة سببها نقص حجم الدم (نزيف، جفاف، أو حروق)."},
    {text:"Mention 4 signs of Hypovolemic Shock.", translation:"اذكر 4 علامات لصدمة نقص الحجم.", answer:"Hypotension, Tachycardia, Pale cold skin, and Oliguria.", answerTranslation:"انخفاض ضغط الدم، تسرع النبض، جلد شاحب بارد، وقلة التبول."},
    {text:"What is Septic Shock?", translation:"ما هي صدمة الإنتان؟", answer:"Shock caused by severe generalized infection (Septicemia) and bacterial toxins.", answerTranslation:"صدمة سببها عدوى معممة شديدة وسموم بكتيرية."},
    {text:"Define Chronic Inflammation.", translation:"عرّف الالتهاب المزمن.", answer:"Prolonged inflammation (weeks/months) characterized by fibrosis and tissue destruction.", answerTranslation:"التهاب مطول (أسابيع/أشهر) يتميز بالتليف وتدمير الأنسجة."},
    {text:'What is "Specific Inflammation"?', translation:'ما هو "الالتهاب النوعي"؟', answer:"Inflammation caused by a specific organism producing a specific tissue reaction (e.g., TB).", answerTranslation:"التهاب يسببه ميكروب محدد يُنتج استجابة نسيجية مميزة (مثل السل)."},
    {text:"What are the functions of Sodium (Na) in the body?", translation:"ما وظائف الصوديوم بالجسم؟", answer:"Regulating osmotic pressure, water balance, and nerve impulse transmission.", answerTranslation:"تنظيم الضغط الأسموزي، وتوازن الماء، ونقل السيالة العصبية."},
    {text:"Define Hyponatremia.", translation:"عرّف نقص صوديوم الدم.", answer:"A decrease in serum sodium concentration below 135 mEq/L.", answerTranslation:"انخفاض تركيز صوديوم المصل عن 135 ملي مكافئ/لتر."},
    {text:"What are the causes of Hyperkalemia?", translation:"ما أسباب فرط بوتاسيوم الدم؟", answer:"Renal failure, excessive potassium intake, and extensive tissue trauma/burns.", answerTranslation:"الفشل الكلوي، الإفراط بتناول البوتاسيوم، والرضح أو الحروق الواسعة."},
    {text:"List the clinical features of Hypocalcemia.", translation:"اذكر الأعراض السريرية لنقص كالسيوم الدم.", answer:"Tetany, muscle cramps, tingling, and positive Chvostek's/Trousseau's signs.", answerTranslation:"التكزز، تشنجات عضلية، تنميل، وإيجابية علامتي شفوستيك وتروسو."},
    {text:"Explain Chvostek's sign.", translation:"اشرح علامة شفوستيك.", answer:"Twitching of facial muscles in response to tapping over the facial nerve.", answerTranslation:"ارتعاش عضلات الوجه استجابة للنقر فوق مسار العصب الوجهي."},
    {text:"What is Trousseau's sign?", translation:"ما هي علامة تروسو؟", answer:"Carpal spasm induced by inflating a BP cuff above systolic pressure for 3 minutes.", answerTranslation:"تشنج الرسغ الناتج عن نفخ رباط ضغط الدم فوق الضغط الانقباضي لمدة 3 دقائق."},
    {text:"Define Osmosis.", translation:"عرّف التناضح.", answer:"Movement of water through a semi-permeable membrane from low to high solute concentration.", answerTranslation:"انتقال الماء عبر غشاء شبه منفذ من التركيز المنخفض إلى المرتفع."},
    {text:"What is Dehydration?", translation:"ما هو الجفاف؟", answer:"Condition resulting from excessive loss of body water and electrolytes.", answerTranslation:"حالة ناتجة عن فقد مفرط لماء الجسم والشوارد."},
    {text:"Mention 3 signs of severe dehydration.", translation:"اذكر 3 علامات للجفاف الشديد.", answer:"Dry tongue, sunken eyeballs, and loss of skin elasticity (poor turgor).", answerTranslation:"جفاف اللسان، غؤور العينين، وضعف مرونة الجلد."},
    {text:"What is an Isotonic solution? Give an example.", translation:"ما هو المحلول متساوي التوتر؟ اذكر مثالاً.", answer:"A solution with the same osmotic pressure as plasma (e.g., 0.9% Normal Saline).", answerTranslation:"محلول له نفس الضغط الأسموزي للبلازما (مثل المحلول الملحي 0.9%)."},
    {text:"Define Metabolic Acidosis.", translation:"عرّف الحماض الاستقلابي.", answer:"Decrease in blood pH due to loss of bicarbonate or accumulation of acids.", answerTranslation:"انخفاض حموضة الدم (pH) بسبب فقد البيكربونات أو تراكم الأحماض."},
    {text:"What is the nursing care for a patient with Tetanus?", translation:"ما هي الرعاية التمريضية لمريض الكزاز؟", answer:"Dark/quiet room, avoid stimulation, monitor respiration, and high-calorie nutrition.", answerTranslation:"غرفة مظلمة هادئة، تجنب المثيرات، مراقبة التنفس، وتغذية عالية السعرات."},
    {text:"What is the primary treatment for an Abscess?", translation:"ما هو العلاج الأساسي للخراج؟", answer:"Incision and drainage (I&D) of the pus.", answerTranslation:"الشق والتصريف للصديد."},
    {text:"Define Gangrene.", translation:"عرّف الغرغرينا.", answer:"Death and putrefaction of body tissues due to loss of blood supply.", answerTranslation:"موت وتعفن أنسجة الجسم بسبب انقطاع التروية الدموية."},
    {text:"What is a Carbuncle?", translation:"ما هي الجمرة الجلدية؟", answer:"Cluster of connected boils forming a large infection with multiple openings.", answerTranslation:"تجمع دمامل متصلة يُشكّل عدوى كبيرة بفتحات متعددة."},
    {text:"Differentiate between Lymphangitis and Lymphadenitis.", translation:"فرّق بين التهاب الأوعية الليمفاوية والتهاب العقد الليمفاوية.", answer:"Lymphangitis: inflammation of vessels; Lymphadenitis: inflammation of nodes.", answerTranslation:"التهاب الأوعية الليمفاوية: التهاب في الأوعية؛ التهاب العقد الليمفاوية: التهاب في العقد."},
    {text:"What causes Anaphylactic Shock?", translation:"ما سبب الصدمة التأقية؟", answer:"Severe allergic reaction (e.g., Penicillin, insect stings, or foods).", answerTranslation:"رد فعل تحسسي شديد (مثل البنسلين، لدغات الحشرات، أو بعض الأطعمة)."},
    {text:'What is the "Golden Hour" in trauma?', translation:'ما هي "الساعة الذهبية" في الرضح؟', answer:"The first hour after injury where prompt treatment has the highest survival chance.", answerTranslation:"أول ساعة بعد الإصابة يكون فيها العلاج الفوري ذا أعلى فرصة للنجاة."},
    {text:"List 3 complications of IV therapy.", translation:"اذكر 3 مضاعفات للعلاج الوريدي.", answer:"Phlebitis, Hematoma, and Fluid overload (Pulmonary edema).", answerTranslation:"التهاب الوريد، الورم الدموي، وفرط الحمل السائلي (الوذمة الرئوية)."},
    {text:"Define Toxemia.", translation:"عرّف التسمم الدموي.", answer:"The presence of bacterial toxins in the blood.", answerTranslation:"وجود سموم بكتيرية بالدم."},
    {text:"What is a Fistula?", translation:"ما هو الناسور؟", answer:"Abnormal track between two epithelial-lined surfaces (e.g., rectum and skin).", answerTranslation:"مسار غير طبيعي يصل بين سطحين مبطنين بالظهارة (مثل المستقيم والجلد)."},
    {text:"What is a Sinus?", translation:"ما هو الجيب (السينوس)؟", answer:"A blind track lined by granulation tissue opening on one end to a surface.", answerTranslation:"مسار أعمى مبطن بنسيج حبيبي يفتح من طرف واحد على سطح."},
    {text:"Explain the importance of Potassium (K) for the heart.", translation:"اشرح أهمية البوتاسيوم للقلب.", answer:"Essential for cardiac rhythm; imbalance causes dangerous arrhythmias.", answerTranslation:"ضروري لنظم القلب؛ واختلاله يسبب اضطرابات نظم خطيرة."},
    {text:"How do you treat Hypovolemic Shock?", translation:"كيف تُعالَج صدمة نقص الحجم؟", answer:"Stop the cause (bleeding), give IV fluids (Ringer's/Saline), and provide oxygen.", answerTranslation:"إيقاف السبب (النزيف)، إعطاء محاليل وريدية (رينجر/ملحي)، وتوفير الأكسجين."},
    {text:"What is the role of Vitamin D in calcium balance?", translation:"ما دور فيتامين د في توازن الكالسيوم؟", answer:"Necessary for the absorption of calcium from the gastrointestinal tract.", answerTranslation:"ضروري لامتصاص الكالسيوم من الجهاز الهضمي."},
    {text:"Define Erysipelas.", translation:"عرّف مرض الحمرة.", answer:"Superficial cellulitis (Streptococcus pyogenes) with bright red skin.", answerTranslation:"التهاب نسيج خلوي سطحي (بالعقديات المقيحة) مع احمرار جلدي زاهٍ."},
    {text:"What is the incubation period for Tetanus?", translation:"ما هي فترة حضانة الكزاز؟", answer:"Usually 3 to 21 days (shorter means more severe).", answerTranslation:"عادة من 3 إلى 21 يوماً (كلما قصرت زادت شدة المرض)."},
    {text:"Mention the symptoms of Water Intoxication.", translation:"اذكر أعراض التسمم المائي.", answer:"Headache, confusion, nausea, and seizures due to cerebral edema.", answerTranslation:"صداع، تشوش ذهني، غثيان، ونوبات تشنجية بسبب الوذمة الدماغية."},
    {text:'What is "Debridement"?', translation:'ما هو "التنضير"؟', answer:"Surgical removal of dead/infected tissue to improve wound healing.", answerTranslation:"إزالة جراحية للأنسجة الميتة/المصابة لتحسين التئام الجرح."},
    {text:"How can Tetanus be prevented?", translation:"كيف يمكن الوقاية من الكزاز؟", answer:"Active immunization (Tetanus Toxoid) and proper wound cleaning.", answerTranslation:"التطعيم الفعال (الذوفان الكزازي) وتنظيف الجرح بشكل صحيح."},
    {text:"List signs of inflammation in a surgical wound.", translation:"اذكر علامات الالتهاب بالجرح الجراحي.", answer:"Redness, localized swelling, pain, and purulent discharge (pus).", answerTranslation:"احمرار، تورم موضعي، ألم، وإفراز قيحي (صديد)."},
    {text:"Define Hypernatremia.", translation:"عرّف فرط صوديوم الدم.", answer:"Increase in serum sodium concentration above 145 mEq/L.", answerTranslation:"ارتفاع تركيز صوديوم المصل فوق 145 ملي مكافئ/لتر."},
    {text:"What is the main cause of Respiratory Alkalosis?", translation:"ما السبب الرئيسي للقلاء التنفسي؟", answer:"Hyperventilation (excessive breathing) leading to excessive loss of CO2.", answerTranslation:"فرط التهوية (تنفس مفرط) مؤدياً لفقد زائد لثاني أكسيد الكربون."},
    {text:'What is the significance of the "Fluctuation Test" in an abscess?', translation:'ما أهمية "اختبار التموج" في الخراج؟', answer:"Indicates presence of liquid (pus) and that the abscess is ready for incision.", answerTranslation:"يدل على وجود سائل (صديد) وأن الخراج جاهز للشق."}
  ]
};
